import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import axios from "../api/axios";
import "./styles/Home.css";

function Home() {
  const navigate = useNavigate();
  const [trendingBooks, setTrendingBooks] = useState([]);

  // Reveal animation
  useEffect(() => {
    const elements = document.querySelectorAll(".reveal");

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("active");
          }
        });
      },
      { threshold: 0.15 }
    );

    elements.forEach((el) => observer.observe(el));

    return () => {
      elements.forEach((el) => observer.unobserve(el));
    };
  }, []);

  // Fetch trending books
  useEffect(() => {
    const fetchTrending = async () => {
      try {
        const res = await axios.get("/books");

        // Create copy before shuffle (important)
        const shuffled = [...res.data].sort(() => Math.random() - 0.5);

        setTrendingBooks(shuffled.slice(0, 8));
      } catch (err) {
        console.log("Trending fetch error:", err);
      }
    };

    fetchTrending();
  }, []);

  return (
    <div className="home">

      {/* HERO */}
      <section className="hero">
        <div className="hero-left reveal">
          <h1>
            Where stories <br />
            <span>sleep in shelves.</span>
          </h1>

          <p>
            A calm digital library where books are discovered,
            remembered, and quietly treasured.
          </p>

          <button onClick={() => navigate("/auth")}>
            ENTER THE ARCHIVES
          </button>
        </div>

        <div className="hero-right floating">
          <img
            src="https://images.unsplash.com/photo-1524995997946-a1c2e315a42f"
            alt="library"
          />
        </div>
      </section>

      {/* TRENDING BOOKS */}
      <section className="trending-section reveal">
        <div className="trending-header">
          <h2>Trending Books</h2>
          <p>Popular reads curated for you</p>
        </div>

        <div className="trending-slider">
          <div className="trending-track">
            {trendingBooks.map((book) => (
              <div
                key={book._id}
                className="trend-card"
                onClick={() =>
                  navigate(
                    `/book/${encodeURIComponent(book.title)}/${encodeURIComponent(book.author)}/${encodeURIComponent(book.cover)}`
                  )
                }
              >
                <img src={book.cover} alt={book.title} />
                <h4>{book.title}</h4>
                <span>{book.author}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ABOUT */}
      <section className="about-section reveal">
        <div className="about-wrap">
          <div className="about-left">
            <h2>Built for readers, not noise.</h2>
            <p>
              BookSphere is a calm digital library for students and librarians.
              Organize collections, discover books, and manage reading with clarity.
            </p>

            <div className="about-features">
              <div className="feature">📚 Curated Collections</div>
              <div className="feature">🧑‍🎓 Student Friendly</div>
              <div className="feature">🗂 Librarian Control</div>
            </div>
          </div>

          <div className="about-right">
            <img
              src="https://images.unsplash.com/photo-1521587760476-6c12a4b040da"
              alt="Library workspace"
            />
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer reveal">
        <p>BookSphere • Crafted for learning • 2026</p>
      </footer>

    </div>
  );
}

export default Home;
